def fixture(name: str):
    return json.loads(FIXTURES.joinpath(name).read_text(encoding='utf-8'))

class CollectorGoldenTests(unittest.TestCase):

    def test_otel_usage_golden(self):
        batch = ClaudeOTelAdapter().parse_event(fixture('otel_api_request.json'), collected_at=NOW)
        record = next((item for item in batch.records if isinstance(item, UsageRecord)))
        self.assertEqual(record_to_dict(record), OTEL_USAGE)

    def test_hook_model_observation_golden_with_evidence_correction(self):
        batch = ClaudeHookAdapter().parse_event(fixture('hook_agent_posttooluse.json'), source_version='2.1.214', collected_at=NOW)
        record = next((item for item in batch.records if isinstance(item, ModelObservationRecord)))
        self.assertEqual(record_to_dict(record), HOOK_MODEL_OBSERVATION)

    def test_transcript_deduped_usage_golden(self):
        batch = ClaudeTranscriptAdapter().parse_jsonl(FIXTURES.joinpath('transcript_2_1_214.jsonl').read_text(encoding='utf-8'), source_version='2.1.214', collected_at=NOW)
        record = next((item for item in batch.records if isinstance(item, UsageRecord) and item.agent_id == 'agent-synthetic'))
        self.assertEqual(record_to_dict(record), TRANSCRIPT_USAGE)
if __name__ == '__main__':
    unittest.main()
